This is the code and content structure for my personal website. I want you to substatnailly improve this. make it polished and look exceptional


"use client";

import React, { useEffect } from "react";
import { motion } from "framer-motion";

// ---------------------------------------------------------------------------
// SINGLE‑FILE PORTFOLIO (Next.js + Tailwind)
// Includes: Hero, Case Studies, Resume (ATS), Proof, Writing, Personal, Pets,
// CS Skins, Work Style, About, Contact. Dev smoke tests catch content issues.
// ---------------------------------------------------------------------------

// --- QUICK EDITS ------------------------------------------------------------
const DATA = {
  name: "Mohsin (Mo) Fazal Dingankar",
  title: "Assistant Director of Product · Fintech · Credit Cards & Loans",
  tag: "Evidence-first portfolio of a product leader who ships.",
  location: "Gurgaon, India",
  headshot: "https://avatars.githubusercontent.com/u/000000?v=4", // replace
  email: "mohsin@example.com", // replace
  github: "https://github.com/mohsinfd", // replace
  linkedin: "https://www.linkedin.com/in/mohsinfd", // replace
  cv: "/mohsin-dingankar-cv.pdf", // place file in public/
  x: "https://x.com/mohsinfd", // optional
  summary:
    "I build consumer fintech products that convert: card/loan marketplaces, API platforms, and data engines. I care about clarity, velocity, and measurable impact.",
  highlights: [
    { kpi: "2M+", label: "Users batch‑processed via CardGenius server jobs (PoC)" },
    { kpi: "50K/wk", label: "Scalable weekly recos throughput target" },
    { kpi: "100+", label: "Credit cards mapped with benefits taxonomy (ongoing)" },
  ],
  caseStudies: [
    {
      id: "cardgenius",
      title: "CardGenius: Spend‑based credit card recommendations",
      timeframe: "2024–2025",
      role: "Owner: Product, GTM, data model, partner APIs",
      problem:
        "Users pick wrong cards due to opaque benefits and scattered info; high drop‑offs on generic lists.",
      approach: [
        "Defined benefits taxonomy (cashback, lounge, fuel, e‑com) and category questions",
        "Designed init→calculate API flow; added privacy/Incognito mode",
        "Built lead gen flow with secondary CTA to expert consult without cannibalizing main journey",
      ],
      impact: [
        "Improved click→lead by surfacing brand‑specific pages (e.g., Best for Amazon/Flipkart)",
        "Unlocked SEO surfaces: category pages, LTF pages, MITC tables",
      ],
      tech: ["Next.js", "Tailwind", "Node", "Postman", "BigQuery/GA4"],
      links: [
        { label: "Demo / Live", href: "#" },
        { label: "API Spec", href: "#" },
        { label: "PRD", href: "#" },
      ],
    },
    {
      id: "loans",
      title: "Loans vertical: Fibe integration & eligibility flows",
      timeframe: "2025",
      role: "Product lead: listing, eligibility, BRE inputs, UAT→Prod",
      problem:
        "Fragmented loan discovery and mismatched eligibility created low approval and poor UX.",
      approach: [
        "Standardised BRE inputs and lead schema; set partner token/env toggles",
        "Wrote living PRDs and mock UX with dataset fixtures for Cursor builds",
      ],
      impact: [
        "Faster partner onboarding; cleaner analytics events; clearer TAT for ops",
      ],
      tech: ["Next.js", "REST", "JWT", "Supabase"],
      links: [
        { label: "Flow Mock", href: "#" },
        { label: "Partner Docs", href: "#" },
      ],
    },
  ],
  proof: [
    { label: "GitHub", href: "https://github.com/mohsinfd" },
    { label: "Resume/CV", href: "/mohsin-dingankar-cv.pdf" },
    { label: "Selected PRDs", href: "#" },
    { label: "Talks / Interviews", href: "#" },
  ],
  writing: [
    {
      title: "Evidence‑first product pages",
      href: "#",
      tldr: "Replace fluff with real problems and measurable outcomes.",
    },
    {
      title: "Designing brand‑specific credit card surfaces",
      href: "#",
      tldr: "Users search by intent (Amazon, Flipkart); meet them there.",
    },
  ],
  skills: [
    "PRDs & live specs",
    "API contracts (cards, loans)",
    "Data pipelines & analytics",
    "SEO systems",
    "Partnership GTM",
    "Team orchestration",
  ],
  tools: [
    "Next.js",
    "Tailwind",
    "Node/Express",
    "Postman",
    "Supabase/SQL",
    "GA4/Clevertap",
    "Vercel",
  ],
  // --- Personal profile -----------------------------------------------------
  personal: {
    bio: "Partner to Ragini, dad to Mizu. Building products, stories, and a sane life. Gamer at heart (Counter‑Strike), reader, and design tinkerer.",
    interests: [
      "Parenting & routines",
      "Gaming & modding",
      "Writing essays/poetry",
      "History & politics",
      "Dogs & cats (Hopey, Lalu, Bob, Lovu)",
    ],
    now: [
      "Designing CardGenius v2 surfaces",
      "Parenting experiments: meals, sleep, play",
      "Writing small essays on process & craft",
    ],
    links: [
      { label: "Personal notes", href: "#" },
      { label: "Poems / Essays", href: "#" },
    ],
  },
  // --- Pets -----------------------------------------------------------------
  pets: [
    { name: "Hopey", species: "Dog", traits: ["Indie x Jack Russell", "trained", "park sprinter"], photo: "#" },
    { name: "Lovu", species: "Cat", traits: ["Indie", "dominant", "black/grey/green markings"], photo: "#" },
    { name: "Lalu", species: "Cat", traits: ["Indie‑Persian mix", "renal diet", "no litter box"], photo: "#" },
    { name: "Bob", species: "Cat", traits: ["1‑year", "gentle", "newest"], photo: "#" },
  ],
  // --- Counter‑Strike Skins -------------------------------------------------
  csSkins: [
    // Example entries — replace image URLs and add more
    { title: "AK‑47 | Redline (FT)", image: "#", story: "First trade‑up win; kept it for the recoil pattern sessions." },
    { title: "M4A1‑S | Printstream (MW)", image: "#", story: "Reward for a clutch streak; my go‑to on Mirage and Ancient." },
  ],
  // --- Work Style ------------------------------------------------------------
  workStyle: {
    headline: "How I work with founders & teams",
    principles: [
      "Evidence &gt; adjectives — instrument early, decide with data.",
      "0→1 in slices — scope thin end‑to‑end, then widen.",
      "APIs first — public contracts before pixels; docs are the product.",
      "Quality bar — fast is fine, sloppy is not.",
      "Owner mindset — write PRDs, test, and unblock across functions.",
    ],
    collaboration: [
      "Single source of truth: living PRD + Postman collection.",
      "Weekly cadence: goals, risks, demo; daily Slack standups async.",
      "Design‑in‑the‑loop: UX in phases, edge cases tracked as checklists.",
      "Analytics: GA4/Clevertap events defined with IDs before build.",
    ],
    zeroToOne: [
      "Define problem/constraints → write PRD v0 with metrics.",
      "Model data contracts, stub APIs, create fixtures & sample events.",
      "Build vertical slice (init→result) with observability.",
      "Ship to staging, record user flows, tighten copy.",
      "Gate to prod behind feature flag; add support playbooks & SOPs.",
    ],
  },
};

// Inline ATS resume text for copy/download
const RESUME_TXT = `ATS RESUME (1 page, copy-paste)

MOHSIN DINGANKAR
Gurgaon, India | +91 98206 92913 | mohsinfd@gmail.com | linkedin.com/in/mohsindingankar

ASSOCIATE DIRECTOR, PRODUCT | FINTECH + CONSUMER GROWTH | API-FIRST PLATFORMS | AI-ACCELERATED DELIVERY
Product leader with 10+ years across mobile, web, and API products in B2C (fintech, gaming, travel, loyalty) and B2B (SaaS, enterprise). Strong IC bias even in leadership roles: I design mechanisms, instrument loops, and ship. Built products in high-complexity environments including KYC/compliance flows across 150+ countries and loyalty ecosystems touching 700M+ user profiles.

EXPERIENCE

CashKaro / BankKaro (Pouring Pounds India Pvt Ltd) — Associate Director, Product (Product Lead/HoP, BankKaro) | Gurgaon | Jun 2024 – Present
Took BankKaro + CardGenius from 0-to-1 within ~12 months; owned product strategy, PRDs/DRDs, UX direction, and go-live readiness.
Created CardGenius: rupee-accurate, spend-based credit card recommendation engine; shipped category mini-calculators to reduce cognitive load and improve decision confidence.
Built the API stack from scratch with an API-first platform architecture; delivered bank integrations with Axis and SBI; HDFC integration in progress.
Operationalized AI-led whitelabeling: generated demo-ready product frontends with minimal engineering involvement; demos delivered to Moneycontrol, Mint, and influencers (Ankur Warikoo, Neha Nagar, Aly Hajiani).
Enabled an org-wide shift to AI-led prototyping (ChatGPT to Cursor) to compress iteration cycles across product teams.

FanClash — Head of Product | Gurgaon | Jul 2022 – Aug 2023
Led a 12-member PM/analytics org; established GTM and KPI operating cadence and weekly experimentation loops.
Scaled DAUs from ~3K to 40K+ in 6 months; grew paying user base 300%; improved MoM retention ~25% to ~40%.
Launched world’s first Live Fantasy (engagement ~40s to ~120s); shipped Switch Fantasy (patent in process) and Fantasy Royale (INR 1L+ top prize).
Built a B2B Computer Vision scoring product for PUBG/BGMI/Valorant/CS where structured scoring data is scarce.

HotelsAroundYou.com — Co-Founder & Chief Product Officer | Mumbai | Jan 2013 – May 2016
Owned apps, web, APIs, and third-party integrations; managed 6 developers plus agencies/freelancers.
Led supply contracting and account management across Western India (200+ hotels); owned customer sales/support and post-sales ops; partnered on fundraising and P&L.

Selected Product Leadership — Western Union, Bizongo/Artwork Flow, Zolo, Loylty Rewardz, Musafir | 2016 – 2022
Owned KYC/compliance + new-user conversion funnels (Western Union, 150+ countries).
Built and pivoted an enterprise SaaS MVP (Artwork Flow) with 12+ enterprise clients; DRI across acquisition to onboarding to success.
Scaled product org and shipped internal ops products (Zolo); owned 17 loyalty apps and points redemption systems at 700M+ profile scale (Loylty Rewardz); delivered funnel revamps across travel booking journeys (Musafir).

EDUCATION
UC San Diego (UCSD) — M.A., International Relations (2009–2011)
University of Mumbai — B.E., Electronics Engineering (2003–2008)

CORE STRENGTHS
API/platform product; fintech integrations; KYC/compliance-aware UX; conversion + retention loops; 0-to-1 builds; AI-assisted prototyping workflows; B2B SaaS + enterprise onboarding; cross-functional leadership with strong IC execution.
`;

// --- LIGHT RUNTIME CHECKS (DEV TESTS) --------------------------------------
function assert(condition, message) {
  if (!condition) throw new Error(`Portfolio test failed: ${message}`);
}

function isHttpUrl(str) {
  try {
    const u = new URL(str);
    return u.protocol === "http:" || u.protocol === "https:";
  } catch {
    return false;
  }
}

function runSmokeTests() {
  try {
    // Core fields
    assert(typeof DATA.name === "string" && DATA.name.length > 0, "DATA.name missing");
    assert(typeof DATA.title === "string" && DATA.title.length > 0, "DATA.title missing");

    // Case studies present
    assert(Array.isArray(DATA.caseStudies) && DATA.caseStudies.length >= 1, "No case studies");
    DATA.caseStudies.forEach((cs, idx) => {
      assert(cs.id && cs.title, `Case study ${idx} missing id/title`);
      assert(cs.problem && Array.isArray(cs.approach) && Array.isArray(cs.impact), `Case study ${cs.id} missing problem/approach/impact`);
      if (Array.isArray(cs.links)) {
        cs.links.forEach((l, j) => {
          assert(typeof l.label === "string" && typeof l.href === "string", `Case study ${cs.id} link ${j} malformed`);
        });
      }
    });

    // Links
    DATA.proof.forEach((p) => assert(typeof p.href === "string", `Proof link malformed: ${p.label}`));

    // Basic contact checks
    assert(DATA.email.includes("@"), "Email looks invalid");
    assert(isHttpUrl(DATA.github), "GitHub URL invalid");
    assert(isHttpUrl(DATA.linkedin), "LinkedIn URL invalid");

    // Resume presence & size
    assert(typeof RESUME_TXT === "string" && RESUME_TXT.length > 500, "Resume text too short/missing");

    // Personal section
    assert(!!DATA.personal && typeof DATA.personal.bio === "string", "Personal bio missing");
    assert(Array.isArray(DATA.personal.interests) && DATA.personal.interests.length >= 3, "Personal interests too short");

    // Pets
    assert(Array.isArray(DATA.pets) && DATA.pets.length === 4, "Pets list should include Hopey + 3 cats");

    // CS Skins
    assert(Array.isArray(DATA.csSkins) && DATA.csSkins.length >= 1, "Add at least one CS skin");

    // Work style
    assert(!!DATA.workStyle && Array.isArray(DATA.workStyle.principles) && DATA.workStyle.principles.length >= 3, "Work style principles missing");
    assert(Array.isArray(DATA.workStyle.zeroToOne) && DATA.workStyle.zeroToOne.length >= 3, "0→1 process bullets missing");

    // Guard: avoid raw HTML‑like tags inside copy that could confuse .jsx pastes
    const forbiddenTagLike = /<[^>]+>/g;
    assert(!forbiddenTagLike.test(RESUME_TXT), "Resume contains raw '<tag>' sequences that could break .jsx pastes");
  } catch (e) {
    // eslint-disable-next-line no-console
    console.error(e);
  }
}

// --- UI HELPERS -------------------------------------------------------------
const Section = ({ id, title, children }) => (
  <section id={id} className="scroll-mt-24 py-14">
    <h2 className="text-2xl md:text-3xl font-semibold tracking-tight mb-6">{title}</h2>
    {children}
  </section>
);

const Badge = ({ children }) => (
  <span className="inline-flex items-center rounded-full border px-3 py-1 text-xs md:text-sm">
    {children}
  </span>
);

const Card = ({ children }) => (
  <div className="rounded-2xl border p-5 md:p-6 shadow-sm bg-white/60 backdrop-blur">
    {children}
  </div>
);

const LinkBtn = ({ href, children }) => (
  <a
    href={href}
    className="inline-flex items-center justify-center rounded-xl border px-4 py-2 text-sm font-medium hover:shadow-md"
  >
    {children}
  </a>
);

// --- PAGE -------------------------------------------------------------------
export default function PortfolioMo() {
  useEffect(() => {
    if (process.env.NODE_ENV !== "production") runSmokeTests();
  }, []);

  return (
    <div className="min-h-screen bg-gradient-to-b from-slate-50 via-white to-slate-50 text-slate-900">
      <nav className="sticky top-0 z-50 border-b bg-white/80 backdrop-blur">
        <div className="mx-auto max-w-6xl px-4 py-3 flex items-center justify-between">
          <a href="#top" className="font-semibold">Mo Dingankar</a>
          <div className="hidden md:flex gap-5 text-sm">
            <a href="#work" className="hover:opacity-80">Work</a>
            <a href="#resume" className="hover:opacity-80">Resume</a>
            <a href="#personal" className="hover:opacity-80">Personal</a>
            <a href="#pets" className="hover:opacity-80">Pets</a>
            <a href="#cs" className="hover:opacity-80">CS Skins</a>
            <a href="#workstyle" className="hover:opacity-80">Work Style</a>
            <a href="#proof" className="hover:opacity-80">Proof</a>
            <a href="#writing" className="hover:opacity-80">Writing</a>
            <a href="#about" className="hover:opacity-80">About</a>
            <a href="#contact" className="hover:opacity-80">Contact</a>
          </div>
        </div>
      </nav>

      {/* HERO */}
      <header id="top" className="mx-auto max-w-6xl px-4 pt-12 md:pt-20">
        <div className="grid grid-cols-1 md:grid-cols-[1.2fr_0.8fr] gap-8 items-center">
          <div>
            <motion.h1
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5 }}
              className="text-3xl md:text-5xl font-bold tracking-tight"
            >
              {DATA.name}
            </motion.h1>
            <p className="mt-2 text-lg md:text-xl opacity-80">{DATA.title}</p>
            <p className="mt-4 text-base md:text-lg max-w-2xl">{DATA.summary}</p>
            <div className="mt-6 flex flex-wrap gap-3">
              <Badge>{DATA.location}</Badge>
              {DATA.tools.slice(0, 4).map((t) => (
                <Badge key={t}>{t}</Badge>
              ))}
            </div>
            <div className="mt-6 flex gap-3">
              <LinkBtn href={DATA.cv}>Download CV</LinkBtn>
              <LinkBtn href={DATA.github}>GitHub</LinkBtn>
              <LinkBtn href={DATA.linkedin}>LinkedIn</LinkBtn>
            </div>
            <div className="mt-8 grid grid-cols-3 md:grid-cols-6 gap-4">
              {DATA.highlights.map((h) => (
                <Card key={h.kpi}>
                  <div className="text-2xl md:text-3xl font-semibold">{h.kpi}</div>
                  <div className="text-xs md:text-sm opacity-80 mt-1">{h.label}</div>
                </Card>
              ))}
            </div>
          </div>
          <div className="flex md:justify-end">
            <div className="relative w-40 h-40 md:w-60 md:h-60 rounded-3xl overflow-hidden border shadow-lg">
              <img src={DATA.headshot} alt="Mo" className="w-full h-full object-cover" />
            </div>
          </div>
        </div>
      </header>

      <main className="mx-auto max-w-6xl px-4">
        {/* WORK */}
        <Section id="work" title="Selected Work (case studies)">
          <div className="grid md:grid-cols-2 gap-6">
            {DATA.caseStudies.map((cs) => (
              <Card key={cs.id}>
                <div className="flex items-start justify-between gap-4">
                  <div>
                    <h3 className="text-xl font-semibold">{cs.title}</h3>
                    <p className="text-sm opacity-70">{cs.timeframe} · {cs.role}</p>
                  </div>
                  <div className="text-xs opacity-70 whitespace-nowrap">{cs.tech.join(" · ")}</div>
                </div>
                <div className="mt-4">
                  <h4 className="text-sm font-medium">Problem</h4>
                  <p className="text-sm opacity-90">{cs.problem}</p>
                </div>
                <div className="mt-3">
                  <h4 className="text-sm font-medium">Approach</h4>
                  <ul className="list-disc pl-5 text-sm opacity-90 space-y-1">
                    {cs.approach.map((a, i) => <li key={i}>{a}</li>)}
                  </ul>
                </div>
                <div className="mt-3">
                  <h4 className="text-sm font-medium">Impact</h4>
                  <ul className="list-disc pl-5 text-sm opacity-90 space-y-1">
                    {cs.impact.map((a, i) => <li key={i}>{a}</li>)}
                  </ul>
                </div>
                <div className="mt-4 flex flex-wrap gap-2">
                  {cs.links.map((l) => (
                    <LinkBtn key={l.label} href={l.href}>{l.label}</LinkBtn>
                  ))}
                </div>
              </Card>
            ))}
          </div>
        </Section>

        {/* RESUME */}
        <Section id="resume" title="Resume (ATS, 1-page)">
          <Card>
            <div className="flex flex-wrap items-center gap-3 mb-4">
              <LinkBtn href={DATA.cv}>Download PDF</LinkBtn>
              <button
                onClick={() => navigator.clipboard.writeText(RESUME_TXT)}
                className="inline-flex items-center justify-center rounded-xl border px-4 py-2 text-sm font-medium hover:shadow-md"
              >Copy as Text</button>
              <a
                href={`data:text/plain;charset=utf-8,${encodeURIComponent(RESUME_TXT)}`}
                download="Mohsin-Dingankar-ATS-Resume.txt"
                className="inline-flex items-center justify-center rounded-xl border px-4 py-2 text-sm font-medium hover:shadow-md"
              >Download .txt</a>
            </div>
            <pre className="whitespace-pre-wrap font-mono text-sm leading-6">{RESUME_TXT}</pre>
          </Card>
        </Section>

        {/* PROOF */}
        <Section id="proof" title="Proof of Work (artifacts)">
          <div className="grid sm:grid-cols-2 md:grid-cols-4 gap-4">
            {DATA.proof.map((p) => (
              <a key={p.label} href={p.href} className="group">
                <Card>
                  <div className="text-sm font-medium group-hover:underline">{p.label}</div>
                  <div className="text-xs opacity-70 mt-1">Links to real docs, repos, and specs.</div>
                </Card>
              </a>
            ))}
          </div>
        </Section>

        {/* WRITING */}
        <Section id="writing" title="Writing">
          <div className="grid md:grid-cols-2 gap-4">
            {DATA.writing.map((w) => (
              <a key={w.title} href={w.href} className="group">
                <Card>
                  <div className="text-base md:text-lg font-semibold group-hover:underline">{w.title}</div>
                  <div className="text-sm opacity-80 mt-1">{w.tldr}</div>
                </Card>
              </a>
            ))}
          </div>
        </Section>

        {/* PERSONAL */}
        <Section id="personal" title="Beyond Work (life)">
          <div className="grid md:grid-cols-3 gap-6">
            <Card>
              <h3 className="font-semibold mb-2">Snapshot</h3>
              <p className="text-sm opacity-90">{DATA.personal.bio}</p>
            </Card>
            <Card>
              <h3 className="font-semibold mb-2">Interests</h3>
              <div className="flex flex-wrap gap-2">
                {DATA.personal.interests.map((s) => <Badge key={s}>{s}</Badge>)}
              </div>
            </Card>
            <Card>
              <h3 className="font-semibold mb-2">Now</h3>
              <ul className="list-disc pl-5 text-sm space-y-1 opacity-90">
                {DATA.personal.now.map((n, i) => <li key={i}>{n}</li>)}
              </ul>
              <div className="mt-3 flex flex-wrap gap-2">
                {DATA.personal.links.map((l) => (
                  <LinkBtn key={l.label} href={l.href}>{l.label}</LinkBtn>
                ))}
              </div>
            </Card>
          </div>
        </Section>

        {/* PETS */}
        <Section id="pets" title="Pets (1 dog + 3 cats)">
          <div className="grid sm:grid-cols-2 md:grid-cols-4 gap-4">
            {DATA.pets.map((p) => (
              <Card key={p.name}>
                <div className="flex items-center gap-3">
                  <div className="w-14 h-14 rounded-xl bg-slate-100 overflow-hidden border">
                    {p.photo !== "#" ? (
                      <img src={p.photo} alt={p.name} className="w-full h-full object-cover" />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center text-xs opacity-60">No photo</div>
                    )}
                  </div>
                  <div>
                    <div className="text-sm font-semibold">{p.name} · {p.species}</div>
                    <div className="text-xs opacity-70">{p.traits.join(", ")}</div>
                  </div>
                </div>
              </Card>
            ))}
          </div>
        </Section>

        {/* COUNTER‑STRIKE SKINS */}
        <Section id="cs" title="Counter‑Strike Skins I Love">
          <div className="grid sm:grid-cols-2 md:grid-cols-3 gap-4">
            {DATA.csSkins.map((s) => (
              <Card key={s.title}>
                <div className="w-full aspect-video rounded-xl bg-slate-100 overflow-hidden border">
                  {s.image !== "#" ? (
                    <img src={s.image} alt={s.title} className="w-full h-full object-cover" />
                  ) : (
                    <div className="w-full h-full flex items-center justify-center text-xs opacity-60">Add image</div>
                  )}
                </div>
                <div className="mt-3 text-sm font-medium">{s.title}</div>
                <div className="text-xs opacity-80 mt-1">{s.story}</div>
              </Card>
            ))}
          </div>
        </Section>

        {/* WORK STYLE */}
        <Section id="workstyle" title="Work Style (for founders & CEOs)">
          <div className="grid md:grid-cols-3 gap-6">
            <Card>
              <h3 className="font-semibold mb-2">Principles</h3>
              <ul className="list-disc pl-5 text-sm space-y-1 opacity-90">
                {DATA.workStyle.principles.map((t, i) => <li key={i} dangerouslySetInnerHTML={{ __html: t }} />)}
              </ul>
            </Card>
            <Card>
              <h3 className="font-semibold mb-2">Collaboration</h3>
              <ul className="list-disc pl-5 text-sm space-y-1 opacity-90">
                {DATA.workStyle.collaboration.map((t, i) => <li key={i}>{t}</li>)}
              </ul>
            </Card>
            <Card>
              <h3 className="font-semibold mb-2">0→1 Process</h3>
              <ol className="list-decimal pl-5 text-sm space-y-1 opacity-90">
                {DATA.workStyle.zeroToOne.map((t, i) => <li key={i}>{t}</li>)}
              </ol>
            </Card>
          </div>
        </Section>

        {/* ABOUT */}
        <Section id="about" title="About">
          <div className="grid md:grid-cols-3 gap-6">
            <Card>
              <h3 className="font-semibold mb-2">Principles</h3>
              <ul className="list-disc pl-5 text-sm space-y-1 opacity-90">
                <li>Evidence &amp;gt; adjectives. Show me the metric.</li>
                <li>Velocity with taste: ship in slices, maintain quality bar.</li>
                <li>Source of truth: living PRDs, API contracts, real data.</li>
